$(document).ready(function(){var o=$("#menu"),e=$(".header__menu-toggle"),s=$(".menu__close");$(e).on("click",function(e){e.preventDefault(),o.toggleClass("active")}),$(s).on("click touchstart",function(e){e.preventDefault(),o.removeClass("active")}),$(".events").slick({autoplay:!0,arrows:!0,slidesToShow:4,slidesToScroll:1,infinite:!1,responsive:[{breakpoint:991,settings:{slidesToShow:3}},{breakpoint:767,settings:{slidesToShow:2}},{breakpoint:575,settings:{slidesToShow:1}}]})});